{"displayorder":6,"pagetemplateid":"fc18a914-844b-4d5a-8ab2-020e60610c58","parentpageid":"cb403430-2fb9-4936-a45c-db75f161d8ba","partialurl":"edit-registration","isroot":false,"rootwebpageid":"094fae8b-7c09-4e2b-7037-1d7d8873ebe8","title":"Edit Registration","summary":"<p>This is a sample landing page designed to be a starting point for your website</p>","copy":"{% assign id_param = request.params["id"] %}

{% fetchxml events %}
<fetch version="1.0" mapping="logical">
  <entity name="er_event">
    <attribute name="er_eventid" />
    <attribute name="er_eventname" />
    <order attribute="er_eventname" />
  </entity>
</fetch>
{% endfetchxml %}

{% fetchxml userRegistrationDetails %}
<fetch version="1.0" mapping="logical">
  <entity name="er_registration">
    <attribute name="er_registrationid" />
    <attribute name="er_registrantname" />
    <attribute name="er_email" />
    <attribute name="er_event"/>
    <attribute name="er_registrationstatus" />

    <filter>
      <condition attribute="er_registrationid" operator="eq" value="{{ id_param }}" />
    </filter>
  </entity>
</fetch>
{% endfetchxml %}


<div class="container" style="background-color:rgba(255,255,255,0.9); border-radius:10px; padding:20px;">
  <form id="EditRegistrationForm">

    <h2 class="mb-4">Edit Event Registration</h2>

    {% if id_param and userRegistrationDetails.results.entities.size > 0 %}
    {% assign userRegistration = userRegistrationDetails.results.entities[0] %}

    <!-- Registrant Name -->
    <div class="mb-3">
      <label class="form-label">Registrant Name</label>
      <input type="text" id="registrantName" name="registrantName" class="form-control"
        value="{{ userRegistration.er_registrantname }}" required />
    </div>

    <!-- Email -->
    <div class="mb-3">
      <label class="form-label">Email</label>
      <input type="email" id="email" name="email" class="form-control" value="{{ userRegistration.er_email }}"
        required />
    </div>

    <!-- Registration Status -->
    <div class="mb-3">
      <label class="form-label">Registration Status</label>
      <select id="status" name="status" class="form-control" required>
        <option value="0" {% if userRegistration.er_registrationstatus.value==0 %}selected{% endif %}>Pending</option>
        <option value="1" {% if userRegistration.er_registrationstatus.value==1 %}selected{% endif %}>Confirmed</option>
        <option value="2" {% if userRegistration.er_registrationstatus.value==2 %}selected{% endif %}>Cancelled</option>
      </select>
    </div>
    <!-- Event Dropdown -->
    <div class="form-group mb-3">1{{userRegistration.er_event.value}}2{{userRegistration.er_event.Value}}3{{userRegistration.er_event.label}}4{{userRegistration.er_event.id}}
      <label for="eventRegister" class="form-label"> Event Name:</label>
      <select id="event" name="event" required="" class="form-control">
        <option value="">Select Category</option>
        {% for result in events.results.entities %}
        <p>{{result.er_eventid}} _ {{userRegistration.er_event.id}}</p>
        <option value="{{result.er_eventid}}"{% if userRegistration.er_event.id == {{result.er_eventid}} %}selected{% endif %}>{{ result.er_eventname }}</option>
        {% endfor %}

      </select>
    </div>



    <button type="submit" class="btn btn-primary w-100">Update Registration</button>

    {% else %}
    <div class="alert alert-danger">
      Registration record not found.<br />
      Please check the link or your permissions.
    </div>  
    {% endif %}

  </form>
</div>

{% include "WebAPI Wrapper" %}

<!-- External JS -->
<script src="/webresources/edit-registration.js"></script>","publishingstateid":"706c8d44-f8a7-4d37-803a-01690654b0df","enablerating":false,"enabletracking":false,"excludefromsearch":false,"hiddenfromsitemap":true,"sharedpageconfiguration":false,"feedbackpolicy":756150000,"customjavascript":"document.addEventListener('DOMContentLoaded', function() {
    const form = document.getElementById('EditRegistrationForm');
    if (!form) return;

    form.addEventListener('submit', function(event) {
        event.preventDefault();

        // Grab form values
        const name = document.getElementById('registrantName').value.trim();
        const email = document.getElementById('email').value.trim();
        const eventId = document.getElementById('event').value;
        const status = parseInt(document.getElementById('status').value, 10); // important: convert to integer

        // Get ID from URL
        const url = new URL(window.location.href);
        const id = url.searchParams.get('id');

        if (!id) {
            alert("Registration ID not found in URL!");
            return;
        }

        // PATCH request to update registration
        webapi.safeAjax({
            type: "PATCH",
            url: "/_api/er_registrations(" + id + ")",
            contentType: "application/json",
            data: JSON.stringify({
                er_registrantname: name,
                er_email: email,
                er_registrationstatus: status,
                "er_Event@odata.bind": `/er_events(${eventId})`
            }),
            success: function(res) {
                alert("Registration updated successfully!");
                window.location.href = "/view-my-registration"; // redirect after update
            },
            error: function(err) {
                console.error(err);
                alert("Error updating registration. Check console for details.");
            }
        });
    });
});
"}
